where.if:
AND EXISTS (
    SELECT 1 FROM link_record_tag lrt2
    JOIN tag t2 ON lrt2.tag_id = t2.id
    WHERE lrt2.link_record_id = lr.id AND t2.name = #{filterTag}
)

mapper.select:
SELECT 


GROUP BY lr.id
ORDER BY lr.created_at ${sortDirection}
LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE link_record
SET title = #{title},
    url = #{url},
    url_hash = UNHEX(SHA2(#{url}, 256)),
    status_id = #{statusId}
WHERE id = #{id}
